mapper.select:
SELECT t.id, t.day_entry_id, t.content, t.is_done, t.sort_order
FROM todo t
JOIN day_entry de ON de.id = t.day_entry_id
WHERE t.id = #{id}
  AND de.user_id = #{userId}

mapper.update:
UPDATE todo
SET content = #{content},
    is_done = #{isDone}
WHERE id = #{id}

UPDATE todo
SET sort_order = #{sortOrder}
WHERE id = #{id}

mapper.select:
SELECT MAX(sort_order)
FROM todo
WHERE day_entry_id = #{dayEntryId}
